class Solution {
public:
    vector<int> sequentialDigits(int low, int high) {
        vector<int> result;
        for (int i = 1; i <= 9; ++i) {
            for (int j = i + 1; j <= 9; ++j) {
                for (int k = j + 1; k <= 9; ++k) {
                    for (int l = k + 1; l <= 9; ++l) {
                        for (int m = l + 1; m <= 9; ++m) {
                            int num = i * 1000 + j * 100 + k * 10 + l * 1 + m;
                            if (num >= low && num <= high) {
                                result.push_back(num);
                            }
                        }
                    }
                }
            }
        }
        return result;
    }
};
